(function() {
  try {
    // 複数のパターンでモーダルを閉じるボタンを探す
    const closeButtons = [
      ...Array.from(document.querySelectorAll('button[role="button"]')).filter(b => 
        (b.textContent || '').includes('Got it') || 
        (b.textContent || '').includes('了解') ||
        (b.getAttribute('aria-label') || '').includes('Got it') ||
        (b.getAttribute('aria-label') || '').includes('了解')
      ),
      document.querySelector('[data-testid="app-bar-close"]'),
      document.querySelector('button[aria-label*="Close"]'),
      document.querySelector('button[aria-label*="閉じる"]')
    ].filter(Boolean);

    if (closeButtons.length > 0) {
      closeButtons[0].click();
      return { didAction: true, reason: 'Clicked modal close button' };
    }

    // モーダルが見つからない場合は成功扱い（既に閉じている可能性）
    return { didAction: true, reason: 'Modal close button not found (may already be closed)' };
  } catch(e) {
    return { didAction: false, reason: String(e) };
  }
})()

(async () => {
  const postText = {{db_post_content}};
  const replyTextarea = document.querySelector('[data-testid="tweetTextarea_0"]');

  if (!replyTextarea) { 
    return { didAction: false, reason: 'textarea not found' }; 
  }

  replyTextarea.focus();
  replyTextarea.click();
  await new Promise(r => setTimeout(r, 500));

  // 既存のテキストをクリア
  const range = document.createRange();
  const sel = window.getSelection();
  range.selectNodeContents(replyTextarea);
  range.deleteContents();
  range.collapse(false);
  sel.removeAllRanges();
  sel.addRange(range);
  await new Promise(r => setTimeout(r, 200));

  // テキストを行に分割して処理
  const lines = postText.split('\n');
  let successCount = 0;

  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    // 行のテキストを入力
    if (line.length > 0) {
      for (let i = 0; i < line.length; i++) {
        const char = line[i];
        try {
          // 文字を直接挿入（execCommandの代わりにRange APIを使用）
          const range = document.createRange();
          const sel = window.getSelection();
          if (sel.rangeCount > 0) {
            range.setStart(sel.getRangeAt(0).endContainer, sel.getRangeAt(0).endOffset);
            range.setEnd(sel.getRangeAt(0).endContainer, sel.getRangeAt(0).endOffset);
          } else {
            range.selectNodeContents(replyTextarea);
            range.collapse(false);
          }
          range.deleteContents();
          const textNode = document.createTextNode(char);
          range.insertNode(textNode);
          range.setStartAfter(textNode);
          range.collapse(true);
          sel.removeAllRanges();
          sel.addRange(range);

          // inputイベントを発火
          replyTextarea.dispatchEvent(new Event('input', { bubbles: true, cancelable: true }));
          successCount++;
          await new Promise(r => setTimeout(r, 5));
        } catch (e) {
          return { didAction: false, reason: 'Error at line ' + lineIndex + ', char ' + i + ': ' + String(e) };
        }
      }
    }

    // 最後の行以外は改行を挿入
    if (lineIndex < lines.length - 1) {
      try {
        const range = document.createRange();
        const sel = window.getSelection();
        if (sel.rangeCount > 0) {
          range.setStart(sel.getRangeAt(0).endContainer, sel.getRangeAt(0).endOffset);
          range.setEnd(sel.getRangeAt(0).endContainer, sel.getRangeAt(0).endOffset);
        } else {
          range.selectNodeContents(replyTextarea);
          range.collapse(false);
        }

        // <br>タグを挿入（Xのテキストエリアはcontenteditableのdivなので、<br>タグが有効）
        const br = document.createElement('br');
        range.insertNode(br);
        range.setStartAfter(br);
        range.collapse(true);
        sel.removeAllRanges();
        sel.addRange(range);

        // inputイベントを発火
        replyTextarea.dispatchEvent(new Event('input', { bubbles: true, cancelable: true }));
        successCount++;
        await new Promise(r => setTimeout(r, 10));
      } catch (e) {
        // <br>タグの挿入に失敗した場合、execCommandを試す
        try {
          document.execCommand('insertLineBreak', false);
          replyTextarea.dispatchEvent(new Event('input', { bubbles: true, cancelable: true }));
          successCount++;
          await new Promise(r => setTimeout(r, 10));
        } catch (e2) {
          return { didAction: false, reason: 'Error inserting line break at line ' + lineIndex + ': ' + String(e2) };
        }
      }
    }
  }

  await new Promise(r => setTimeout(r, 500));
  replyTextarea.dispatchEvent(new Event('input', { bubbles: true, cancelable: true }));
  replyTextarea.dispatchEvent(new Event('change', { bubbles: true, cancelable: true }));
  await new Promise(r => setTimeout(r, 1000));

  // テキスト取得方法を改善（innerHTMLからテキストを抽出）
  const getTextContent = (element: HTMLElement): string => {
    // innerHTMLから<br>タグを改行文字に変換してテキストを取得
    const html = element.innerHTML || '';
    const text = html
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<div>/gi, '\n')
      .replace(/<\/div>/gi, '')
      .replace(/<[^>]+>/g, '')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'");
    return text.trim();
  };

  const finalText = getTextContent(replyTextarea) || replyTextarea.textContent || replyTextarea.innerText || '';
  const expectedText = postText;

  return { 
    didAction: true, 
    reason: 'Text input completed', 
    finalTextLength: finalText.length, 
    expectedTextLength: expectedText.length,
    successCount,
    textMatches: finalText === expectedText,
    finalTextPreview: finalText.substring(0, 100),
    expectedTextPreview: expectedText.substring(0, 100)
  };
})()

(function() { 
  try { 
    // 複数の方法でボタンを探す
    let btn = null;

    // 方法1: data-testid
    btn = document.querySelector('[data-testid="tweetButton"]') ||
          document.querySelector('[data-testid="tweetButtonInline"]');

    // 方法2: テキストコンテンツで "Post" を含むボタンを探す
    if (!btn) {
      btn = Array.from(document.querySelectorAll('button')).find(b => {
        const text = (b.textContent || '').trim();
        return text === 'Post' && !b.disabled;
      });
    }

    // 方法3: aria-label
    if (!btn) {
      btn = document.querySelector('button[aria-label*="Post"]') || 
            document.querySelector('button[aria-label*="投稿"]');
    }

    if (btn && !btn.disabled) { 
      btn.click(); 
      return { didAction: true, reason: 'post button clicked' }; 
    } 

    return { didAction: false, reason: btn ? 'post button disabled' : 'post button not found' }; 
  } catch(e) { 
    return { didAction: false, reason: String(e) }; 
  } 
})()
